const plc = 'line-a';
const state = flow.get('slmpMultiMonitorState') || {};
const previous = state[plc] && state[plc].state;
state[plc] = { state: previous === 'reconnecting' ? 'recovered' : 'connected', backoff: 1000 };
flow.set('slmpMultiMonitorState', state);
const timestamp = new Date().toISOString();
const values = msg.payload || {};
msg.payload = Object.entries(values).map(([tag, value]) => ({ timestamp, plc, tag, value }));
msg.state = state[plc].state;
return msg;

