const plc = 'line-a';
const state = flow.get('slmpMultiMonitorState') || {};
const current = state[plc] || { backoff: 1000 };
const status = { plc, state: 'lost', retryMs: current.backoff, error: msg.error || msg.payload };
msg.delay = current.backoff;
msg.topic = 'reinitialize';
msg.reinitialize = true;
msg.state = 'reconnecting';
msg.payload = status;
state[plc] = { state: 'reconnecting', backoff: Math.min(current.backoff * 2, 30000) };
flow.set('slmpMultiMonitorState', state);
return [msg, { payload: status }];

